import java.nio.ByteBuffer;
import java.util.Scanner;

public class SecureBufferHandling {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.println("Enter a string:");

        String userInput = scanner.nextLine();

        // Allocate a ByteBuffer with user input length
        ByteBuffer buffer = ByteBuffer.allocate(userInput.length());

        // Put user input into the buffer
        buffer.put(userInput.getBytes());

        // Reset position to 0 before reading from buffer
        buffer.rewind();

        byte[] outputBytes = new byte[buffer.remaining()];

        // Get bytes from buffer safely
        buffer.get(outputBytes);

        System.out.println("Buffer content: " + new String(outputBytes));
    }
}

